vanilla-js-script:
var MONTHS = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec']
var INITIAL = { labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul'], values: [42, 61, 45, 78, 52, 89, 66] }

var state = {
  labels: INITIAL.labels.slice(),
  values: INITIAL.values.slice(),
  monthCursor: INITIAL.labels.length, // next month to append
  insertCount: 0,
}

// Deterministic "random" value so the demo replays identically.
function nextValue(seed) {
  return 30 + ((seed * 37) % 60)
}

function monthLabel(i) {
  var name = MONTHS[i % 12]
  return i > 11 ? name + " '26" : name
}

function speed() {
  return document.getElementById('dt-slow').checked ? 1800 : 650
}

function pushState() {
  var payload = {
    chart: { animations: { dynamicAnimation: { speed: speed() } } },
    xaxis: { categories: state.labels.slice() },
  }
  chart.updateOptions(
    Object.assign({ series: [{ name: 'Revenue', data: state.values.slice() }] }, payload),
    false,
    true
  )
  chart1.updateOptions(
    Object.assign(
      {
        series: [
          {
            name: 'Users',
            data: state.values.map(function (v) {
              return Math.round(v * 0.6 + 10)
            }),
          },
        ],
      },
      payload
    ),
    false,
    true
  )
  syncButtons()
}

function syncButtons() {
  document.getElementById('dt-add').disabled = state.labels.length >= 20
  document.getElementById('dt-insert').disabled = state.labels.length >= 20
  document.getElementById('dt-remove-last').disabled = state.labels.length <= 3
  document.getElementById('dt-remove-mid').disabled = state.labels.length <= 3
}

document.getElementById('dt-add').addEventListener('click', function () {
  state.labels.push(monthLabel(state.monthCursor))
  state.values.push(nextValue(state.monthCursor))
  state.monthCursor++
  pushState()
})

document.getElementById('dt-insert').addEventListener('click', function () {
  var at = Math.floor(state.labels.length / 2)
  state.insertCount++
  state.labels.splice(at, 0, 'New ' + state.insertCount)
  state.values.splice(at, 0, nextValue(state.insertCount * 5 + 3))
  pushState()
})

document.getElementById('dt-remove-last').addEventListener('click', function () {
  state.labels.pop()
  state.values.pop()
  pushState()
})

document.getElementById('dt-remove-mid').addEventListener('click', function () {
  var at = Math.floor(state.labels.length / 2)
  state.labels.splice(at, 1)
  state.values.splice(at, 1)
  pushState()
})

document.getElementById('dt-rotate').addEventListener('click', function () {
  state.values.push(state.values.shift())
  pushState()
})

document.getElementById('dt-reset').addEventListener('click', function () {
  state.labels = INITIAL.labels.slice()
  state.values = INITIAL.values.slice()
  state.monthCursor = INITIAL.labels.length
  state.insertCount = 0
  pushState()
})

syncButtons()
